 18	
 19	const PasswordSecretFieldsEditSection: FC<CredentialsEditModeByTypeProps> = ({
 20	  onNewSecretChange,
 21	  secret,
 22	}) => {
 23	  const { t } = useForkliftTranslation();
 24	
 25	  const username = getDecodedValue(secret?.data?.username);
 26	  const password = getDecodedValue(secret?.data?.password);
 27	  const regionName = getDecodedValue(secret?.data?.regionName);
 28	  const projectName = getDecodedValue(secret?.data?.projectName);
 29	  const domainName = getDecodedValue(secret?.data?.domainName);
 30	
 31	  const [passwordHidden, setPasswordHidden] = useState<boolean>(true);
 32	
 33	  const [usernameValidation, setUsernameValidation] = useState<ValidationMsg>(
 34	    openstackSecretFieldValidator(OpenstackSecretFieldsId.Username, username!),
 35	  );
 36	
 37	  const [passwordValidation, setPasswordValidation] = useState<ValidationMsg>(
 38	    openstackSecretFieldValidator(OpenstackSecretFieldsId.Password, password!),
 39	  );
 40	
 41	  const [regionNameValidation, setRegionNameValidation] = useState<ValidationMsg>(
 42	    openstackSecretFieldValidator(OpenstackSecretFieldsId.RegionName, regionName!),
 43	  );
 44	  const [projectNameValidation, setProjectNameValidation] = useState<ValidationMsg>(
 45	    openstackSecretFieldValidator(OpenstackSecretFieldsId.ProjectName, projectName!),
 46	  );
 47	
 48	  const [domainNameValidation, setDomainNameValidation] = useState<ValidationMsg>(
 49	    openstackSecretFieldValidator(OpenstackSecretFieldsId.DomainName, domainName!),
 50	  );
 51	
 52	  const handleChange = useCallback(
 53	    (id: OpenstackSecretFieldsId, value: string) => {
 54	      const validationState = openstackSecretFieldValidator(id, value);
 55	
 56	      if (id === OpenstackSecretFieldsId.Username) setUsernameValidation(validationState);
 57	      if (id === OpenstackSecretFieldsId.Password) setPasswordValidation(validationState);
 58	      if (id === OpenstackSecretFieldsId.RegionName) setRegionNameValidation(validationState);
 59	      if (id === OpenstackSecretFieldsId.ProjectName) setProjectNameValidation(validationState);
 60	      if (id === OpenstackSecretFieldsId.DomainName) setDomainNameValidation(validationState);
 61	
 62	      const encodedValue = encode(value?.trim() ?? '');
 63	
 64	      onNewSecretChange({ ...secret, data: { ...secret.data, [id]: encodedValue } });
 65	    },
 66	    [secret, onNewSecretChange],
 67	  );
 68	
 69	  const onClickTogglePassword = () => {
 70	    setPasswordHidden(!passwordHidden);
 71	  };
 72	
 73	  const onChangeFactory: onChangeFactoryType = (changedField) => (_event, value) => {
 74	    handleChange(changedField as OpenstackSecretFieldsId, value);
 75	  };
 76	
 77	  return (
 78	    <>
 79	      <OpenstackUsernameEditItem
 80	        usernameValidation={usernameValidation}
 81	        username={username}
 82	        onChangeFactory={onChangeFactory}
 83	      />
 84	
 85	      <FormGroupWithHelpText
 86	        label={t('Password')}
 87	        isRequired
 88	        fieldId={OpenstackSecretFieldsId.Password}
 89	        helperText={passwordValidation.msg}
 90	        helperTextInvalid={passwordValidation.msg}
 91	        validated={passwordValidation.type}
 92	      >
 93	        <InputGroup>
 94	          <TextInput
 95	            spellCheck="false"
 96	            isRequired
 97	            type={passwordHidden ? 'password' : 'text'}
 98	            aria-label="Password input"
 99	            value={password}
100	            onChange={onChangeFactory(OpenstackSecretFieldsId.Password)}
101	            validated={passwordValidation.type}
102	          />
103	          <Button
104	            variant={ButtonVariant.control}
105	            onClick={onClickTogglePassword}
106	            aria-label={passwordHidden ? 'Show password' : 'Hide password'}
107	          >
108	            {passwordHidden ? <EyeIcon /> : <EyeSlashIcon />}
109	          </Button>
110	        </InputGroup>
111	      </FormGroupWithHelpText>
112	
113	      <OpenstackRegionEditItem
114	        regionNameValidation={regionNameValidation}
115	        regionName={regionName}
116	        onChangeFactory={onChangeFactory}
117	      />
118	
119	      <OpenstackProjectEditItem
120	        projectNameValidation={projectNameValidation}
121	        projectName={projectName}
122	        onChangeFactory={onChangeFactory}
123	      />
124	
125	      <OpenstackDomainEditItem
126	        domainNameValidation={domainNameValidation}
127	        domainName={domainName}
128	        onChangeFactory={onChangeFactory}
129	      />
130	    </>
131	  );
132	};
133	
134	export default PasswordSecretFieldsEditSection;

